/* Scripted terminal-syscall return codes supplied by the CBMC models in
 * stubs/rawmode.c: rm_isatty is isatty()'s result, rm_tcget tcgetattr()'s and
 * rm_tcset tcsetattr()'s.  They make enableRawMode's outcome a deterministic
 * function of these globals so the contract below can pin it exactly.
 * Referenced only by the contract; a normal build needs no definition. */
extern int rm_isatty;
extern int rm_tcget;
extern int rm_tcset;
extern int rm_errno; /* the object behind errno; see stubs/rawmode.c */

/* Raw mode: 1960 magic shit. */
int enableRawMode(int fd)
    /* Verify the not-yet-enabled path (the early "already enabled" return is a
     * trivial no-op outside the mutated branches). */
    __CPROVER_requires(E.rawmode == 0)
    __CPROVER_assigns(E.rawmode, rm_errno)
    __CPROVER_ensures(__CPROVER_return_value == 0 || __CPROVER_return_value == -1)
    /* Success (return 0, raw mode now on) happens exactly when the terminal is a
     * tty and both tcgetattr() and tcsetattr() succeed; any other combination
     * takes the fatal path.  Pinning this exact relationship to the three
     * scripted return codes kills every comparison-operator mutant on the
     * tcgetattr()/tcsetattr() error checks. */
    __CPROVER_ensures((__CPROVER_return_value == 0) ==
        (rm_isatty != 0 && rm_tcget != -1 && rm_tcset >= 0))
    __CPROVER_ensures((E.rawmode == 1) == (__CPROVER_return_value == 0))
    /* The fatal path always reports ENOTTY (rm_errno is the errno object). */
    __CPROVER_ensures(__CPROVER_return_value == -1 ==> rm_errno == ENOTTY)
{
    struct termios raw;

    if (E.rawmode) return 0; /* Already enabled. */
    if (!isatty(STDIN_FILENO)) goto fatal;
    atexit(editorAtExit);
    if (tcgetattr(fd,&orig_termios) == -1) goto fatal;

    raw = orig_termios;  /* modify the original mode */
    /* input modes: no break, no CR to NL, no parity check, no strip char,
     * no start/stop output control. */
    raw.c_iflag &= ~(BRKINT | ICRNL | INPCK | ISTRIP | IXON);
    /* output modes - disable post processing */
    raw.c_oflag &= ~(OPOST);
    /* control modes - set 8 bit chars */
    raw.c_cflag |= (CS8);
    /* local modes - choing off, canonical off, no extended functions,
     * no signal chars (^Z,^C) */
    raw.c_lflag &= ~(ECHO | ICANON | IEXTEN | ISIG);
    /* control chars - set return condition: min number of bytes and timer. */
    raw.c_cc[VMIN] = 0; /* Return each byte, or zero for timeout. */

